#!/usr/bin/env python3
"""
zip03 — MEMORY PIPELINE HARDENING (fix-plan Phase 1a).
The Vaibhav incident, fixed at three layers:
  1. src/memory.ts REPLACED — third-party rule + durability bar (model-tagged,
     code-enforced) + a temperature-0 VERIFY PASS before any insert + literal-dupe
     guard. fn tags: memory_harvest, memory_verify.
  2. src/memoryGardener.ts NEW — nightly janitor: merges duplicates, resolves
     contradictions (newest wins), pulls transient weeds + third-party rows.
     Model proposes (JSON, temp 0), code applies; never >50% deletions in a pass.
  3. index.ts: founder-gated POST /memory/garden (the one-time cleanup lever).
     overseer-run.ts: gardener rides the existing Railway cron after the overseer.
Anchored, idempotent, atomic. Run from repo root: python3 writer_memory_pipeline.py
Then: npm run build (real gate) → commit → push. Server-only: NO eas update needed.
VERIFICATION IS CREDIT-GATED — see pending-curls.md.
"""
import base64, os, sys

MARKER = '// [zip03]'
FILES = {
  'src/memory.ts': 'MEMORY_B64',
  'src/memoryGardener.ts': 'GARDENER_B64',
}
MEMORY_B64 = ""
GARDENER_B64 = ""

def die(m): print('ABORT: ' + m); sys.exit(1)

def write_atomic(path, content):
    tmp = path + '.tmp'
    open(tmp, 'w', encoding='utf-8').write(content)
    os.replace(tmp, path)

# ── 1+2: drop the two files (memory.ts replaced; gardener new) ──
mem = base64.b64decode(MEMORY_B64).decode('utf-8')
gar = base64.b64decode(GARDENER_B64).decode('utf-8')
if MARKER not in mem or MARKER not in gar: die('embedded files missing marker')
old_mem = open('src/memory.ts', encoding='utf-8').read()
if 'harvestMemory' not in old_mem: die('src/memory.ts does not look like the memory module')
write_atomic('src/memory.ts', mem)
write_atomic('src/memoryGardener.ts', gar)
print('wrote src/memory.ts (hardened) + src/memoryGardener.ts (new)')

# ── 3a: index.ts — import + founder-gated endpoint ──
IDX = 'src/index.ts'
src = open(IDX, encoding='utf-8').read()
IMPORT_ANCHOR = "import { logUsage, costSnapshot, costSince, diagEcho, DIAG_USER_ID } from './usage.js';"
IMPORT_NEW = IMPORT_ANCHOR + "\nimport { gardenUserMemory } from './memoryGardener.js';   // [zip03]"
ROUTE_ANCHOR = "app.get('/battlefield/ready', (_req, res) => {"
ROUTE_NEW = """// [zip03] founder-gated one-shot memory cleanup: garden ONE user's memory rows
// (defaults to the caller). The nightly sweep rides overseer-run; this is the lever.
app.post('/memory/garden', express.json(), async (req, res) => {
  try {
    const authId = await authUser(req);
    if (!authId) return res.status(401).json({ error: 'unauthorized' });
    const user = await resolveUser(authId);
    if (!user || user.id !== DIAG_USER_ID) return res.status(403).json({ error: 'nope' });
    const target = typeof req.body?.userId === 'string' && req.body.userId ? req.body.userId : user.id;
    const summary = await gardenUserMemory(target);
    res.json(summary);
  } catch (e: any) { res.status(500).json({ error: 'garden failed: ' + (e?.message || String(e)) }); }
});

""" + ROUTE_ANCHOR

if 'gardenUserMemory' in src:
    print('index.ts already wired — skipping')
else:
    if src.count(IMPORT_ANCHOR) != 1: die('index.ts import anchor not unique')
    if src.count(ROUTE_ANCHOR) != 1: die('index.ts route anchor not unique')
    src = src.replace(IMPORT_ANCHOR, IMPORT_NEW, 1).replace(ROUTE_ANCHOR, ROUTE_NEW, 1)
    write_atomic(IDX, src)
    print('index.ts: import + POST /memory/garden (founder-gated)')

# ── 3b: overseer-run.ts — the gardener rides the existing cron ──
OVR = 'src/overseer-run.ts'
ors = open(OVR, encoding='utf-8').read()
OLD_RUN = """runOverseer({ weekly: process.argv.includes('weekly'), onlyUser })
  .then((r) => { console.log('[overseer-run]', r); process.exit(0); })
  .catch((e) => { console.error('[overseer-run] failed', e); process.exit(1); });"""
NEW_RUN = """import { gardenAllUsers, gardenUserMemory } from './memoryGardener.js';   // [zip03]
runOverseer({ weekly: process.argv.includes('weekly'), onlyUser })
  .then(async (r) => {
    console.log('[overseer-run]', r);
    // [zip03] the memory gardener rides the same nightly cron. Its failure never
    // marks the run failed — the overseer's work already landed.
    try {
      const g = onlyUser ? await gardenUserMemory(onlyUser) : await gardenAllUsers();
      console.log('[overseer-run] gardener', g);
    } catch (e) { console.error('[overseer-run] gardener failed', e); }
    process.exit(0);
  })
  .catch((e) => { console.error('[overseer-run] failed', e); process.exit(1); });"""
if 'gardenAllUsers' in ors:
    print('overseer-run.ts already wired — skipping')
else:
    if ors.count(OLD_RUN) != 1: die('overseer-run anchor not unique')
    write_atomic(OVR, ors.replace(OLD_RUN, NEW_RUN, 1))
    print('overseer-run.ts: gardener rides the nightly cron')

print('zip03 applied. Gate: npm run build. Verification: pending-curls.md (credit-gated).')
